%[text] # 例10.4（RED法：ノイズ除去による正則化）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2026a
%[text] ## 準備
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example10_04"; %#ok<NASGU>

imgname = "msipimg05";
imgfmt  = "tiff";

rng(0)
close all
%%
%[text] ## 画像データの読込
szOrg = [96 96];
imgfile = fullfile(datfolder,imgname);
X = imresize(im2double(rgb2gray(imread(imgfile,imgfmt))),szOrg,'bilinear');
%%
%[text] ## 観測モデルの設定
%[text] ガウスぼかし + AWGN: $\\mathbf{v}=\\mathbf{Hx}+\\mathbf{w}$
sigmaK = 2.0;
blurKernel = fspecial('gaussian', 9, sigmaK);
H   = @(x)   imfilter(x, blurKernel, 'circular');
Ht  = @(x)   imfilter(x, rot90(blurKernel,2), 'circular');

sigmaW = 5/255;
V = H(X) + sigmaW * randn(size(X));
psnr_obs = psnr(V, X);
fprintf("観測画像 PSNR: %.2f dB\n", psnr_obs) %[output:56d78898]
%%
%[text] ## ノイズ除去器の設定
%[text] RED法の正則化関数:
%[text]  $\\mathfrak{R}\_\\mathrm{RED}(\\mathbf{x})=\\frac{1}{2}\\mathbf{x}^\\top(\\mathbf{x}-f(\\mathbf{x}))$
%[text] その勾配:
%[text]  $\nabla\_\\mathbf{x}\\mathfrak{R}\_\\mathrm{RED}(\\mathbf{x})=\\mathbf{x}-f(\\mathbf{x})$
%[text] ここで $f(\\cdot)$ は AWGN除去器
tnrdFile = fullfile(datfolder,'example10_02_tnrd.mat');
if isfile(tnrdFile) %[output:group:9f0df783]
    S = load(tnrdFile);
    tnrdNet = S.net;
    lambda_tnrd = exp(double(extractdata(S.loglambda)));
    denoiser = @(x) tnrdDenoise(tnrdNet, lambda_tnrd, x);
    fprintf("TNRD除去器を使用\n") %[output:47297d13]
else
    % フォールバック: ガウスフィルタ（非線形除去器の代用）
    sigma_d = 1.5;
    denoiser = @(x) imgaussfilt(x, sigma_d);
    fprintf("ガウスフィルタ除去器を使用 (σ=%.1f)\n", sigma_d)
end %[output:group:9f0df783]
%%
%[text] ## RED-GD法による画像復元
%[text] RED-GD反復:
%[text]  $\\mathbf{x}^{(t+1)}\\leftarrow\\mathbf{x}^{(t)}-\\mu\\left\[\\mathbf{H}^\\top(\\mathbf{H}\\mathbf{x}^{(t)}-\\mathbf{v})+\\lambda(\\mathbf{x}^{(t)}-f(\\mathbf{x}^{(t)}))\right\]$
mu     = 0.5;   % ステップサイズ
lambda = 0.1;   % 正則化パラメータ
nIters = 200;

x_red = V;  % 初期値: 観測画像
psnrs_red = zeros(nIters, 1);

for iter = 1:nIters
    % データフィデリティ項の勾配
    grad_data = Ht(H(x_red) - V);

    % RED正則化項の勾配: x - f(x)
    grad_reg  = x_red - denoiser(x_red);

    % GD更新
    x_red = x_red - mu * (grad_data + lambda * grad_reg);
    x_red = min(max(x_red, 0), 1);
    psnrs_red(iter) = psnr(x_red, X);
end
fprintf("RED-GD PSNR: %.2f dB (反復数: %d)\n", psnrs_red(nIters), nIters) %[output:89e327e8]
%%
%[text] ## ヤコビ行列の対称性の確認
%[text] RED法で対応する正則化関数が存在するための条件:
%[text]  $(\\partial f / \\partial \\mathbf{x})= (\\partial f / \\partial \\mathbf{x})^\\top$ （ヤコビ行列の対称性）
%[text] 数値的に確認（小さいランダムベクトルを用いた有限差分）
N  = numel(X);
ep = 1e-4;
u  = double(X(:));     % テスト点
f_u = denoiser(X);
f_u_vec = f_u(:);

% ランダムな方向 e1, e2 で (e1^T * J * e2) と (e2^T * J * e1) を比較
rng(1)
e1 = randn(N,1); e1 = e1/norm(e1);
e2 = randn(N,1); e2 = e2/norm(e2);

% J * e1 ≈ (f(u + ε*e1) - f(u)) / ε
f_pe1 = denoiser(reshape(u + ep*e1, szOrg));
Je1 = (f_pe1(:) - f_u_vec) / ep;

% e2^T * J * e1
e2_Je1 = e2' * Je1;

% J * e2 ≈ (f(u + ε*e2) - f(u)) / ε
f_pe2 = denoiser(reshape(u + ep*e2, szOrg));
Je2 = (f_pe2(:) - f_u_vec) / ep;

% e1^T * J * e2
e1_Je2 = e1' * Je2;

fprintf("ヤコビ行列対称性の確認:\n") %[output:2c85c95f]
fprintf("  e2^T J e1 = %.6f\n", e2_Je1) %[output:95edbde2]
fprintf("  e1^T J e2 = %.6f\n", e1_Je2) %[output:915fec76]
fprintf("  差 |e2^TJe1 - e1^TJe2| = %.2e\n", abs(e2_Je1 - e1_Je2)) %[output:576b2d03]
%%
%[text] ## ウィナーフィルタによる比較
H_freq = psf2otf(blurKernel, szOrg);
snr_est = 1 / sigmaW^2;
X_wiener = real(ifft2(fft2(V) .* conj(H_freq) ./ (abs(H_freq).^2 + 1/snr_est)));
X_wiener = min(max(X_wiener, 0), 1);
psnr_wiener = psnr(X_wiener, X);
fprintf("ウィナーフィルタ PSNR: %.2f dB\n", psnr_wiener) %[output:0fcba57c]
%%
%[text] ## 結果の表示
fontSize = 14;

figure(1) %[output:346f601b]
subplot(1,4,1); imshow(X);        title('原画像','FontSize',12) %[output:346f601b]
subplot(1,4,2); imshow(V);        title(sprintf('観測 (%.2f dB)',psnr_obs),'FontSize',12) %[output:346f601b]
subplot(1,4,3); imshow(X_wiener); title(sprintf('ウィナー (%.2f dB)',psnr_wiener),'FontSize',12) %[output:346f601b]
subplot(1,4,4); imshow(x_red);    title(sprintf('RED-GD (%.2f dB)',psnrs_red(nIters)),'FontSize',12) %[output:346f601b]
imwrite(x_red, fullfile(resfolder,'fig10-04a.png'))

figure(2) %[output:907b0dc8]
plot(1:nIters, psnrs_red, 'k-', 'LineWidth', 1.5) %[output:907b0dc8]
xlabel('反復数','FontSize',fontSize) %[output:907b0dc8]
ylabel('PSNR [dB]','FontSize',fontSize) %[output:907b0dc8]
yline(psnr_wiener,'k--','LineWidth',1.5,'Label','ウィナーフィルタ') %[output:907b0dc8]
title('RED-GD: PSNRの収束') %[output:907b0dc8]
set(gca,'FontSize',fontSize) %[output:907b0dc8]
grid on %[output:907b0dc8]
set(gcf,'PaperUnits','inches','PaperSize',[8.26 5.16],'PaperPosition',[0 0 8.26 5.16])
print(gcf, fullfile(resfolder,'fig10-04b.png'),'-dpng','-r96') %[output:907b0dc8]

%%
%[text] ## 【関数定義】

function x_out = tnrdDenoise(net, lambda, x)
%TNRDDENOISE  TNRD除去器の適用
x_s  = single(x);
V_dl = dlarray(x_s, 'SSCB');
g_V  = predict(net, V_dl);
x_out = double(x_s) - lambda * double(extractdata(g_V));
end

